<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="utf-8">
<title>Falling Sand Sandbox</title>
<style>
  body{margin:0;background:#222;color:#eee;font-family:sans-serif;display:flex;flex-direction:column;align-items:center;}
  #controls{margin-top:10px;}
  button{background:#444;border:none;padding:6px 12px;margin:2px;color:white;cursor:pointer;border-radius:4px;}
  button.active{background:#888;}
  canvas{border:1px solid #555;background:#111;}
</style>
</head>
<body>
<canvas id="sand" width="400" height="400"></canvas>
<div id="controls">
  <button id="mat-sand">Sand</button>
  <button id="mat-water">Water</button>
  <button id="mat-wall">Wall</button>
  <button id="mat-acid">Acid</button>
  <button id="mat-empty">Eraser</button>
  <button id="clear">Clear</button>
</div>

<script>
(() => {
  const canvas = document.getElementById('sand');
  const ctx = canvas.getContext('2d');
  const w = 80, h = 80; // grid size
  const cellSize = canvas.width / w;
  const materials = ['empty','sand','water','wall','acid'];
  let grid = new Array(w*h).fill('empty');

  function idx(x,y){return y*w+x;}
  function get(x,y){
    if(x<0||x>=w||y<0||y>=h)return 'wall';
    return grid[idx(x,y)];
  }
  function set(x,y,mat){
    if(x<0||x>=w||y<0||y>=h)return;
    grid[idx(x,y)]=mat;
  }

  // API
  window.sim = {w,h,tick,get,set,clear};

  function clear(){grid.fill('empty');}

  function tick(n=1){
    for(let step=0;step<n;step++){
      const moved = new Array(w*h).fill(false);
      for(let y=h-2;y>=0;y--){ // bottom row cannot move down
        for(let x=0;x<w;x++){
          const i=idx(x,y);
          if(moved[i])continue;
          const mat=get(x,y);
          if(mat==='empty'||mat==='wall')continue;
          let movedThis=false;
          if(mat==='sand'){
            // try fall
            if(get(x,y+1)==='empty'){set(x,y+1,'sand');set(x,y,'empty');moved[idx(x,y+1)]=true; movedThis=true;}
            else if(['water','acid'].includes(get(x,y+1))){set(x,y+1,'sand');set(x,y,get(x,y+1));moved[idx(x,y+1)]=true; movedThis=true;}
            else{
              // slide
              const dirs=[-1,1];
              if(Math.random()<0.5)dirs.reverse();
              for(const d of dirs){
                if(get(x+d,y+1)==='empty'){set(x+d,y+1,'sand');set(x,y,'empty');moved[idx(x+d,y+1)]=true; movedThis=true;break;}
              }
            }
          }else if(mat==='water'||mat==='acid'){
            // fall
            if(get(x,y+1)==='empty'){set(x,y+1,mat);set(x,y,'empty');moved[idx(x,y+1)]=true; movedThis=true;}
            else{
              // spread horizontally
              const dirs=[-1,1];
              if(Math.random()<0.5)dirs.reverse();
              for(const d of dirs){
                if(get(x+d,y)==='empty'){set(x+d,y,mat);set(x,y,'empty');moved[idx(x+d,y)]=true; movedThis=true;break;}
              }
            }
          }
          // acid dissolving
          if(mat==='acid' && !movedThis){
            const dirs=[-1,0,1];
            for(const d of dirs){
              const nx=x+d, ny=y+1;
              const target=get(nx,ny);
              if(['sand','wall'].includes(target)){
                set(nx,ny,'empty'); // dissolve
              }
            }
          }
          moved[i]=movedThis;
        }
      }
    }
  }

  function draw(){
    ctx.clearRect(0,0,canvas.width,canvas.height);
    for(let y=0;y<h;y++){
      for(let x=0;x<w;x++){
        const mat=get(x,y);
        if(mat==='empty')continue;
        switch(mat){
          case 'sand':ctx.fillStyle='#D2B48C';break;
          case 'water':ctx.fillStyle='#00AEEF';break;
          case 'wall':ctx.fillStyle='#555';break;
          case 'acid':ctx.fillStyle='#8B0000';break;
        }
        ctx.fillRect(x*cellSize,y*cellSize,cellSize,cellSize);
      }
    }
  }

  // Animation loop
  function loop(){
    tick();
    draw();
    requestAnimationFrame(loop);
  }
  requestAnimationFrame(loop);

  // UI
  let currentMat='sand';
  const buttons = {
    'mat-sand':'sand',
    'mat-water':'water',
    'mat-wall':'wall',
    'mat-acid':'acid',
    'mat-empty':'empty'
  };
  for(const id in buttons){
    document.getElementById(id).addEventListener('click',()=>{
      currentMat=buttons[id];
      Object.values(buttons).forEach((_,k)=>document.getElementById(`mat-${_}`).classList.remove('active'));
      document.getElementById(id).classList.add('active');
    });
  }
  document.getElementById('clear').addEventListener('click',clear);

  let painting=false;
  canvas.addEventListener('mousedown',(e)=>{
    painting=true;
    paintAt(e);
  });
  canvas.addEventListener('mousemove',(e)=>{if(painting)paintAt(e);});
  canvas.addEventListener('mouseup',()=>painting=false);
  canvas.addEventListener('mouseleave',()=>painting=false);

  function paintAt(e){
    const rect=canvas.getBoundingClientRect();
    const x=Math.floor((e.clientX-rect.left)/cellSize);
    const y=Math.floor((e.clientY-rect.top)/cellSize);
    set(x,y,currentMat);
  }
})();
</script>
</body>
</html>
